INSERT INTO "data_migrations" VALUES('schema_v2_evidence_sources_2026-05-11','2026-05-11T18:57:14+00:00','migration_v2_authors_language_translation','session_2026-05-11-schema-migration','Migrated evidence_sources to v2 schema: normalized authors table, language detection, translations, structured bibliographic fields. 675 rows, 816 author rows.');
