INSERT INTO "data_migrations" VALUES('items_applicable_groups_normalization_2026-05-11','2026-05-11T23:32:55+00:00','three_tables_populations_links_elaborations','session_2026-05-11-items-population-normalization','Normalized items.applicable_groups CSV into populations + item_population_links + item_population_elaborations. Migrated 361 links across 91 items. 3 elaboration rows for wheelchair/upper-limb sub-spec variants. Dropped applicable_groups column.');
INSERT INTO "data_migrations" VALUES('verification_pipeline_v1_columns_2026-05-12','2026-05-12 02:37','add_verified_by_tool_last_verified_at_attempt_count_superseded_by','session_2026-05-12-verification-pipeline-v1','V1 schema additions per proposal §6');
INSERT INTO "data_migrations" VALUES('pipeline_runs_table_2026-05-12','2026-05-12 02:49','create_pipeline_runs_table_for_sqlite_native_run_tracking','session_2026-05-12-workflow-update','Adds pipeline_runs table for SQLite-native run state tracking. Replaces temp-file approach in GitHub Actions workflow. Each run writes pre/post counts and per-phase results. Per user direction: state tracking commensurate with repo SQLite structures.');
INSERT INTO "data_migrations" VALUES('metadata_enrichment_columns_2026-05-12','2026-05-12 03:12','add_pages_pub_month_language_subtype_citation_count','session_2026-05-12-metadata-maximize','Per user direction: maximize CrossRef/PubMed metadata capture. Adds 5 columns to evidence_sources: pages, pub_month, language, subtype, citation_count. Used by enrich_from_crossref to populate from CrossRef item; will be filled retrospectively by Phase 4 DOI-lookup pass.');
INSERT INTO "data_migrations" VALUES('pipeline_runs_phase_4_columns_2026-05-12','2026-05-12 03:13','add_phase_4_columns_and_metadata_complete_tracking','session_2026-05-12-metadata-maximize','Extends pipeline_runs with Phase 4 (CrossRef DOI-lookup enrichment) metrics and metadata_complete before/after counters.');
INSERT INTO "data_migrations" VALUES('channel_2_url_verification_2026-05-12','2026-05-12 03:50','add_url_columns_and_runs_table','session_2026-05-12-channel2-build','Channel 2 URL verifier V1. Adds 3 columns to evidence_sources (url_resolution_outcome, url_last_fetched, url_match_similarity) and creates url_verification_runs table. Generic URL-fetch + title-match. Wayback fallback on dead URLs. Tested locally 25/25; deploys to GitHub Actions for real network access.');
INSERT INTO "data_migrations" VALUES('iec_60118_4_triplicate_documented_2026-05-12','2026-05-12 15:17','intentional_three_source_rows_same_doi','session_2026-05-12-review','REF-00200 / REF-00328 / REF-00348 all resolve to doi=10.31030/2853913 (DIN EN IEC 60118-4). This is INTENTIONAL — three distinct scope citations within the same standard (loop performance / induction-loop systems / hearing aids Pt4). Not a deduplication error. Confirmed by review 2026-05-12.');
INSERT INTO "data_migrations" VALUES('doi_resolution_outcome_backfill_2026-05-12','2026-05-12 15:17','set_RESOLVED_on_211_pre_pipeline_doi_rows','session_2026-05-12-review','Backfill: set doi_resolution_outcome=RESOLVED on 211 rows that had a manually-entered DOI before the pipeline existed. Makes state machine consistent — pipeline will now correctly treat these as already resolved.');
INSERT INTO "data_migrations" VALUES('verified_by_tool_backfill_2026-05-12','2026-05-12 15:17','set_co1_manual_on_133_mystery_verified_rows','session_2026-05-12-review','Backfill: set verified_by_tool=co1-manual-pre-pipeline on 133 rows that were manually VERIFIED before the pipeline. Makes audit trail honest for rule #10. Does not change verification_status.');
INSERT INTO "data_migrations" VALUES('010_fk_integrity_2026-05-13','2026-05-14 02:07:17','fk_integrity_legacy_to_evidence_sources_4tables_782rows_plus_pmp_fix_5_epm_backfill_gap_id_col','session_2026-05-13b-evidence-verification-methodology','FK integrity fix: 4 tables repointed from evidence_sources_v1_legacy to evidence_sources (782 rows). PMP-A02-001-S2 ref_id fix. 5 evidence_population_match ref_id backfills. gap_id column added. Per DR-2026-05-13.');
INSERT INTO "data_migrations" VALUES('011_reasoning_doc_citations_2026-05-13','2026-05-14 02:08:02','create_reasoning_doc_citations_table_4_indexes_track3_dr_2026-05-13','session_2026-05-13b-evidence-verification-methodology','Track 3 of DR-2026-05-13: create reasoning_doc_citations table with claim_type enum covering numerical, jurisdictional, qualitative, definitional claims. 4 indexes. Backs the sharpened rule #10 sub-rules 2 and 3.');
INSERT INTO "data_migrations" VALUES('track1_backfill_pass1_2026-05-13','2026-05-14 02:09:42','edition_backfill_from_standard_number_publisher_catalog_fetch_41_records','session_2026-05-13b-evidence-verification-methodology','Track 1 first pass per DR-2026-05-13: edition populated on 41 publisher-catalog-fetch records by extracting year/date from standard_number. superseded_by_ref_id NOT auto-populated in this pass; deferred to manual review per rule #1.');
