INSERT INTO "evidence_sources" VALUES('REF-00297','standard',2,1,NULL,NULL,1,'TERRAGON, & Deutscher Städte- und Gemeindebund (DStGB)',2017,'April 2017','Barrierefreies Wohnen im Kostenvergleich — Eine Analyse notwendiger Mehrausgaben gegenüber konventionellen Bauweisen. URL','— 148 DIN 18040-2 criteria; 138 zero-cost; 1.26% full-compliance premium (€21.50/m²)',NULL,NULL,'de','langdetect','Barrier-free construction cost comparison — an analysis of necessary measures',NULL,NULL,NULL,'machine_claude',0,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'DIN 18040-2',NULL,NULL,NULL,NULL,NULL,'https://www.dstgb.de/aktuelles/archiv/archiv-2017/barrierefreiheit-bei-neubauwohnungen-fuer-rund-ein-prozent-der-baukosten-realisierbar/',NULL,NULL,NULL,3,'standard_eb','DE',NULL,NULL,NULL,'AUTHOR-TITLE-ONLY','UNVERIFIED-1',NULL,NULL,NULL,0,NULL,'[session_2026-05-13a-url-verification] URL GET → HTTP 200 text/html. Page is DStGB news release titled ''Barrierefreie Neubauwohnungen für ein Prozent der Baukosten realisierbar'' (DStGB, 2017-04-06). Page describes the TERRAGON + DStGB study by name (''Barrierefreies Wohnen im Kostenvergleich''). DISCREPANCY: DB record title is ''Barrierefreies Bauen im Kostenvergleich — Eine Analyse'' — likely typo ''Bauen''→''Wohnen'' (Wohnen=housing, Bauen=building). Page IS the URL DB points to; page legitimately describes the cited study but is itself a press release, not the study. ACTION: title correction needed (Bauen→Wohnen); consider whether to retain DStGB press release as cited source or replace with the TERRAGON study itself. Flagged for content review.
