INSERT INTO "evidence_sources" VALUES('REF-00710','standard',5,1,'Tola','G., Talu, V., Congiu, T., Bain, P.',0,'Tola, G., Talu, V., Congiu, T., Bain, P., & Lindert, J.',2021,NULL,'Built Environment Design and People with Autism Spectrum Disorder (ASD)','A Scoping Review',NULL,NULL,'en','langdetect',NULL,NULL,NULL,NULL,'native_english',0,NULL,'Int J Environ Res Public Health','18','6','3203',NULL,NULL,'MDPI AG',NULL,NULL,NULL,NULL,NULL,NULL,NULL,'ASD','10.3390/ijerph18063203','33808817',NULL,NULL,'1660-4601',NULL,NULL,NULL,NULL,2,'sr_meta','IT',NULL,NULL,NULL,'COMPLETE','VERIFIED','RESOLVED',NULL,NULL,0,NULL,'evidence_type mapped scoping_review→sr_meta (canonical enum)','Expected to find a systematic or scoping review of autism-built-environment literature. Expected it to confirm thin evidence base given prior session findings.','school autism design evidence limitation built environment Italy scoping review',NULL,'Verified 2026-05-10 via PubMed (PMID 33808817) and PMC (PMC8003767). University of Sassari. Only 21/801 studies met inclusion. Three factors: sensory quality, intelligibility, predictability. KEY ADVERSARIAL: evidence base is thin; focused on children not adults; no urban studies.','2026-05-10T20:36:02Z','session_2026-05-10e-slug3-adversarial','2026-05-12 21:14','session_2026-05-12j-phase-b-verification',NULL,NULL,0,NULL,'3203',3,'en','journal-article',80,NULL,NULL,NULL);
