INSERT INTO "evidence_sources_v1_legacy" VALUES('REF-00701','Unknown (PMC12673401)','2025','Effectiveness of sensory integration-based intervention in autistic children, focusing on Chinese children: a systematic review and meta-analysis','10.3389/fpsyt.2025.1623149',NULL,'PMC12673401',3,'systematic_review_meta_analysis','CN/INT',NULL,'VERIFIED',NULL,NULL,NULL,'SR+MA focusing on Chinese children with ASD receiving SI intervention. Key context: Chinese ASD prevalence 0.7% among school-aged (6-12), ~700,000 affected. Found via multilingual remediation search.
INSERT INTO "evidence_sources_v1_legacy" VALUES('REF-00702','Korean OT researchers (KCI/Korea Science)','2022','Systematic review of SI intervention methods for ASD children in Korea (국내 자폐스펙트럼장애 아동 감각통합 중재방법)','10.18064/jkasi.2022.20.3.48',NULL,NULL,3,'systematic_review','KR',NULL,'PROBABILISTIC',NULL,NULL,NULL,'Korean SR: 10 studies, all showed positive SI effects on ASD children. BUT: predominantly single-subject designs (not RCTs); calls for higher quality evidence. Measures used: Sensory Profile + COPM. Covers clinical intervention, NOT room design or user control.
INSERT INTO "evidence_sources_v1_legacy" VALUES('REF-00703','McKee, Harris, Rice & Silk','2007','Effect of Snoezelen rooms on disturbing behaviour in persons with autism (cited in VISS Skanderborg review)','10.1016/j.ridd.2006.04.001',NULL,NULL,3,'primary_study','INT',NULL,'VERIFIED',NULL,NULL,NULL,'ADVERSARIAL: Found no evidence to support Snoezelen for autism; examples of behavior worsening. Cited in Danish VISS knowledge center review. Directly challenges BPC prior.
