INSERT INTO "evidence_sources_v1_legacy" VALUES('REF-00710','Tola, G., Talu, V., Congiu, T., Bain, P. & Lindert, J.','2021','Built Environment Design and People with Autism Spectrum Disorder (ASD): A Scoping Review. Int J Environ Res Public Health 18(6):3203','10.3390/ijerph18063203',NULL,'33808817',2,'scoping_review','IT',NULL,'VERIFIED',NULL,NULL,NULL,'Verified 2026-05-10 via PubMed (PMID 33808817) and PMC (PMC8003767). University of Sassari. Only 21/801 studies met inclusion. Three factors: sensory quality, intelligibility, predictability. KEY ADVERSARIAL: evidence base is thin; focused on children not adults; no urban studies.','2026-05-10T20:36:02Z','session_2026-05-10e-slug3-adversarial','2026-05-10T20:36:02Z','session_2026-05-10e-slug3-adversarial',NULL,'Expected to find a systematic or scoping review of autism-built-environment literature. Expected it to confirm thin evidence base given prior session findings.','school autism design evidence limitation built environment Italy scoping review',NULL);
INSERT INTO "evidence_sources_v1_legacy" VALUES('REF-00711','Abdelmoula, E., Bouayed Abdelmoula, N. & Abdelmoula, B.','2024','Guidelines of inclusive architecture design for autism spectrum disorder: What is new? European Psychiatry 67(S1):S120-S121','10.1192/j.eurpsy.2024.272',NULL,NULL,2,'review','FR',NULL,'VERIFIED',NULL,NULL,NULL,'Verified 2026-05-10 via PMC (PMC11860188) and Cambridge Core. Tunisian/French team. Confirms Mostafa ASPECTSS as only evidence-based framework. KEY: acoustics is ONE of seven design concepts, not dominant as Simpson 2025 suggests.','2026-05-10T20:36:02Z','session_2026-05-10e-slug3-adversarial','2026-05-10T20:36:02Z','session_2026-05-10e-slug3-adversarial',NULL,'Expected to find French-language autism architecture review. Expected it to reference ASPECTSS framework.','autisme architecture design inclusive critique evidence PMC11860188',NULL);
