INSERT INTO "gaps" VALUES('GAP-034','AUDT','P3','CLOSED-FIXED','functional-deficit-auditor','A-04','FDA-Q2/scope A-04: ALL populations claimed but no population-specific NC thresholds. Spec says sensitive populations NC-25 but does not identify which populations are sensitive. ISW to map populations to NC tiers. [FIXED: population-specific NC tier mapping added to pop_reasons_json]','2026-05-08 21:13','session_2026-05-08-c3-calibration','2026-05-08 21:13','session_2026-05-08-a04-fix',NULL,NULL,NULL,NULL);
