INSERT INTO "gaps" VALUES('GAP-036','AUDT','P3','CLOSED-SYNC','evidence-auditor','A-04','UNSTATED A-04: NC-25/30/35 thresholds, 20m restorative interval — no stratum annotations. Standards-derived consensus = EMERGING. ISW to annotate. [BPC has stratum data (cross-population-conflict-resolutions). Sync to spec.]','2026-05-08 21:13','session_2026-05-08-c3-calibration','2026-05-09 02:01:40','session_2026-05-08-bpc-crossref',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-037','CD','P3','CLOSED-FIXED','content-gap-analyzer','A-04','coverage A-04: No mention of hearing loop provision in acoustically zoned areas. DEAF users need amplification even in NC-25 quiet zones. ISW to cross-reference A-11 (Hearing Loop). [FIXED: A-11 cross-reference added to install_notes]','2026-05-08 21:13','session_2026-05-08-c3-calibration','2026-05-08 21:13','session_2026-05-08-content-fix',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-038','CONF','P2','CLOSED-RESOLVED','cross-population-conflict-mapper','A-04','conflict A-04: ACOUSTIC-LVL domain — DEAF (amplified speech) vs NDV/SENS (quiet). Graduated zoning is an implicit resolution (RESOLVED-CONSENSUS) but not documented as a conflict resolution. ISW to add explicit conflict note referencing ACOUSTIC-LVL domain resolution.','2026-05-08 21:13','session_2026-05-08-c3-calibration','2026-05-09 02:13','session_2026-05-08-gap-resolution',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-039','AUDT','P3','CLOSED-SYSTEMIC','functional-deficit-auditor','B-10','FDA-Q3 B-10: Compensatory FOR correct for DEAF. NDV mechanism is Dunns Sensory Processing (overload), not compensatory. NEU/epilepsy is medical/neurological. DEM is Allens Cognitive. ISW to add per-population mechanism rationales.','2026-05-08 21:14','session_2026-05-08-c3-calibration','2026-05-08 21:14','session_2026-05-08-systemic-collapse',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-040','RP','P2','OPEN','functional-deficit-auditor','B-10','FDA-Q6/FDR B-10: Sequenced multi-modal alarm timing (T+0/3/5s) is novel design without published evaluation. No clinical evidence for the specific timing values. FDR trigger for sequenced alarm effectiveness research. [RESEARCH 2026-05-09: Multi-modal alarm approach supported by literature (Springer 2022 deaf alarm tech, 2025 VR multimodal study, Protec/Cranford sensory sensitivity guidance). Sequential activation principle valid per NDV overload evidence. Red strobe seizure reduction supported. However: specific T+0/3/5s timing values remain novel — no published evaluation of this sequence. Gap stands at P2 for the timing specification.] [VERIFIED: FIA 2022 guidance is real (REF-VERIFIED-007). General multi-modal principle is published; specific T+0/3/5s timing remains novel.]','2026-05-08 21:14','session_2026-05-08-c3-calibration','2026-05-09 23:37','session_2026-05-09-merge-rebase','Recommendation would change if: (a) FIA guidance superseded with different sequencing; (b) IFSM 2024 study or successor shows simultaneous is preferred.','50-65%','Drops to 35-50% if FIA guidance does not address specific T+0/3/5s timing (which it does not). Rises to 75-85% if IFSM 2024 study or successor publishes specific timing evaluation.','PARTIAL VERIFICATION: Prior was wrong. FIA 2022 guidance (REF-VERIFIED-007) addresses sensory-sensitive alarm design. IFSM 2024 study evaluated 4 SEN schools.');
INSERT INTO "gaps" VALUES('GAP-041','AUDT','P3','CLOSED-SYNC','evidence-auditor','B-10','UNSTATED B-10: 0.5 Hz reduced strobe rate — no citation for this specific value. Photosensitive epilepsy threshold (3 Hz) is well-evidenced but 0.5 Hz as the safe alternative is unstated. ISW to add stratum or source. [BPC has stratum data (visual-fire-alarm-seizure-safety). Sync to spec.]','2026-05-08 21:14','session_2026-05-08-c3-calibration','2026-05-09 02:01:40','session_2026-05-08-bpc-crossref',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-042','AUDT','P3','CLOSED-SYNC','evidence-auditor','B-10','UNSTATED B-10: Sequenced alarm T+0/3/5s timing — novel specification, no stratum. ISW to annotate as ABSENT (design principle, no empirical basis) with expert consensus disclosure. [BPC has stratum data (visual-fire-alarm-seizure-safety). Sync to spec.]','2026-05-08 21:14','session_2026-05-08-c3-calibration','2026-05-09 02:01:40','session_2026-05-08-bpc-crossref',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-043','MX','P3','CLOSED-FIXED','content-gap-analyzer','B-10','coverage B-10: DEM evacuation specification limited to staff-mediated. No DEM-specific alarm comprehension design (e.g., familiar voice, simple instruction language, visual instruction display). ISW to develop DEM alarm specification. [FIXED: DEM evacuation note added to install_notes with specific design recommendations]','2026-05-08 21:14','session_2026-05-08-c3-calibration','2026-05-09 05:10','session_2026-05-09-authoring',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-044','CONF','P2','CLOSED-RESOLVED','cross-population-conflict-mapper','B-10','conflict B-10: VIS-COMPLEX (NDV minimal vs DEAF visual redundancy) and ACOUSTIC-LVL (NDV quiet vs DEAF amplified) — both RESOLVED via sequenced multi-modal alarm (CON-0217). Log conflicts as RESOLVED-CONSENSUS with citation to spec.','2026-05-08 21:14','session_2026-05-08-c3-calibration','2026-05-09 02:13','session_2026-05-08-gap-resolution',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-045','CD','P3','OPEN','content-gap-analyzer','B-10','thematic B-10: DBL THIN BASE acknowledged but no DBL-specific alarm testing protocol. Vibrotactile pathway (K-04) is the only DBL channel — single-point-of-failure risk. ISW to note redundancy gap. [FIXED: DBL redundancy protocol added to install_notes] [REOPENED 2026-05-09 21:03: protocol backfill exposed shallow closure — honest re-evaluation needed] [VERIFICATION 2026-05-09 21:07: 30-second threshold confirmed FABRICATED. NFPA 72 has 90s/100s thresholds, not 30s for DBL. install_notes corrected. Gap remains OPEN — actual DBL detection-time research needed.]','2026-05-08 21:14','session_2026-05-08-c3-calibration','2026-05-09 21:07','session_2026-05-09-fabrication-fix','Recommendation would change if: (a) DBL detection-time research with N>20 establishes a population safety threshold; OR (b) NFPA 72 or BS 5839 incorporates DBL-specific detection-time guidance; OR (c) post-occupancy data from DBL alarm installations shows current single-channel approach is acceptable.','20-35%','CI is low because original close included a fabricated 30-second detection threshold. Drops to 10-20% if no peer-reviewed DBL detection-time research can be found. Rises to 50-65% if NFPA 72, BS 5839-9, or DeafBlind International publish specific guidance.','Verified: NFPA 72 references 90s waterflow + 100s FACP processing thresholds, NOT a 30s DBL detection threshold. The 30-second figure I wrote does not appear in NFPA 72 or BS 5839. Deafgard product manual mentions 20s detection from 30s alarm — product spec, not population safety threshold. My original close fabricated authority.');
