INSERT INTO "gaps" VALUES('GAP-083','EC','P3','CLOSED-FIXED','economics-auditor','A-14','EA-C2 A-14: Capital cost indicator absent on HIGH retrofit item. [ECONOMICS-RESEARCH 2026-05-09: Lifecycle evidence: Design-stage accessibility adds 0-0.5% to new construction cost (Schroeder & Steinfeld 1979, HUD). Retrofit costs 50%+ more than design-stage provision (UK Changing Places programm] [FIXED: economics note with lifecycle evidence added] [REOPENED 2026-05-09 21:03: protocol backfill exposed shallow closure — honest re-evaluation needed] [VERIFIED 2026-05-09 21:06: Schroeder & Steinfeld 1979 confirmed real via Google Books, AbeBooks, Springer Nature, Independent Living Institute. Premature reopening reversed.] [STRICT REVIEW 2026-05-10 02:40: Schroeder real but old. Confidence reduced from 60-75% to 40-55%.]','2026-05-09 01:43','session_2026-05-08-c3-batch-a','2026-05-10 02:40','session_2026-05-09-strict-reexam','Recommendation would change if: (a) post-2020 multi-jurisdictional cost study (N>50) shows premium materially exceeds 1%; (b) construction-cost composition shifted; (c) regional differences invalidate global generalization.','40-55%','Drops to 25-35% if 1979 cost data is shown obsolete (47 years of construction-cost evolution). Rises to 65-80% if recent jurisdictional cost studies (post-2020, N>20 buildings) replicate similar premium.','STRICT REVIEW: Schroeder & Steinfeld 1979 IS real but 47 years old, US residential context. The 0.5% figure is widely REPEATED but the original empirical basis may not generalize to current global commercial construction. Each later study (HUD 1988, RHFAC 2024) has its own context.');
INSERT INTO "gaps" VALUES('GAP-084','EC','P3','CLOSED-FIXED','economics-auditor','A-14','EA-C3 A-14: Lifecycle framing absent on HIGH retrofit item. [ECONOMICS-RESEARCH 2026-05-09: Lifecycle evidence: Design-stage accessibility adds 0-0.5% to new construction cost (Schroeder & Steinfeld 1979, HUD). Retrofit costs 50%+ more than design-stage provision (UK Changing Places programm] [FIXED: lifecycle evidence added per Schroeder & Steinfeld, RHFAC 2024] [REOPENED 2026-05-09 21:03: protocol backfill exposed shallow closure — honest re-evaluation needed] [VERIFIED 2026-05-09 21:06: Schroeder & Steinfeld 1979 confirmed.] [STRICT REVIEW 2026-05-10 02:40: Schroeder real but old. Confidence reduced from 60-75% to 40-55%.]','2026-05-09 01:43','session_2026-05-08-c3-batch-a','2026-05-10 02:40','session_2026-05-09-strict-reexam','Recommendation would change if: (a) post-2020 multi-jurisdictional cost study (N>50) shows premium materially exceeds 1%; (b) construction-cost composition shifted; (c) regional differences invalidate global generalization.','40-55%','Drops to 25-35% if 1979 cost data is shown obsolete (47 years of construction-cost evolution). Rises to 65-80% if recent jurisdictional cost studies (post-2020, N>20 buildings) replicate similar premium.','STRICT REVIEW: Schroeder & Steinfeld 1979 IS real but 47 years old, US residential context. The 0.5% figure is widely REPEATED but the original empirical basis may not generalize to current global commercial construction. Each later study (HUD 1988, RHFAC 2024) has its own context.');
