INSERT INTO "gaps" VALUES('GAP-208','EC','P3','CLOSED-FIXED','economics-auditor','G-01','EA-C5 G-01: Safety item — cost-of-not-doing assessment needed. [ECONOMICS-RESEARCH 2026-05-09: Lifecycle evidence: Design-stage accessibility adds 0-0.5% to new construction cost (Schroeder & Steinfeld 1979, HUD). Retrofit costs 50%+ more than design-stage provision (UK Changing Places programm] [FIXED: safety cost-of-not-doing note added] [STRICT REVIEW 2026-05-10 02:40: closure was based on generic regulatory framing without specific evidence trace. Confidence reduced.]','2026-05-09 01:45','session_2026-05-08-c3-batch-all','2026-05-10 02:40','session_2026-05-09-strict-reexam','Recommendation would change if: (a) D-10 specifies values beyond statutory minimum without trace to evidence; (b) jurisdictional review shows fire safety signage compliance not enforced.','45-60%','Drops to 30-45% if D-10 specifies values beyond statutory minimum without supporting evidence. Rises with jurisdictional case-law evidence.','STRICT REVIEW: Generic statutory framing is true but does not validate SPECIFIC guidebook claims. If D-10 specifies values beyond statutory minimum, those specific values lack independent evidence.');
