INSERT INTO "gaps" VALUES('GAP-264','AUDT','P3','OPEN','evidence-auditor','SYSTEMIC','SYSTEMIC: Multilingual search coverage — now documented in search_languages (1134 rows) and search_coverage (1863 rows). BPC files show actual multilingual coverage: EN 59%, DE 53%, JA 40%, FR 38%, ZH 31%, KO 26%. Coverage is better than initially assessed but NOT comprehensive. 21 slugs have no documented EN search. ZH/KO/PT coverage thin. Future research sessions should target NOT-RUN language/jurisdiction combinations for items with SPECULATIVE flags.','2026-05-09 05:27','session_2026-05-09-multijurisdictional','2026-05-09 21:04','session_2026-05-09-honest-backfill-2','Falsification condition will be defined when research is conducted under protocol.','NOT-RESEARCHED','CI cannot be assigned until research is conducted under protocol.','NOT-RESEARCHED — search has not been performed.');
