INSERT INTO "gaps" VALUES('GAP-278','AUDT','P1','OPEN','citation-verifier','accessibility-feature-market-value-uplift-framing','Avandell-NJ 60% revenue premium claim in accessibility-feature-market-value-uplift-framing.md. Highest fabrication risk per RULE 2026-04-09. Economics BPC previously caught with 3 fabricated quantified findings. See bpc-audit-pass1 1A / Pass 2B.5. [PASS-2B VERIFIED 2026-05-10: FABRICATION PATTERN. $12k is projected (not actual) price from CEO interview. $7500 is NJ state avg mislabeled as US avg (actual US avg ~$5650). 60% arithmetic correct but denominator wrong-labeled. No academic source. Consistent with RULE 2026-04-09 economics BPC fabrication pattern.]','2026-05-10 05:59','bpc-audit-2026-05-10','2026-05-10 05:59','bpc-audit-2026-05-10',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-279','AUDT','P2','OPEN','citation-verifier','mental-health-built-environment','MH BPC: Faerden 2022 (PMID 36567605) described as patient-control RCT with Cohen d=2.0. Study is actually pre-post quasi-experimental, staff-rated (not patient-reported). d=2.0 unconfirmed from accessible sources. Study design mischaracterized as Tier 1 RCT. Pass 2B.3 finding.','2026-05-10 06:09','bpc-audit-2026-05-10','2026-05-10 06:09','bpc-audit-2026-05-10',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-280','AUDT','P2','OPEN','citation-verifier','mental-health-built-environment','MH BPC: Weltens 2023 OR 5.36 overcrowding-aggression claim. OR 5.36 not found in accessible Weltens papers. 2021 systematic review (PMID 34624057) reports ORs of 1.30/2.08/2.15 for graduated overcrowding. May be from 2023 BMJ Open ESM study (inaccessible results) or misattributed. Pass 2B.4 finding.','2026-05-10 06:09','bpc-audit-2026-05-10','2026-05-10 06:09','bpc-audit-2026-05-10',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-281','AUDT','P2','OPEN',NULL,'data-quality','Systemic NULL bpc_source_slug across all 91 items in items table. The column was added but never backfilled. Blocks any cross-table query of form ''what items belong to slug X''. Surfaced by audit Stage B.5 (session 2026-05-10c). Resolution path: backfill via either (a) reading each items.bpc_source_slug from the canonical BPC docs, or (b) reverse-derive from co-occurrence in BPC body text. Owner decision needed on resolution path.','2026-05-10T19:35:00Z','session_2026-05-10c-protocol-redo.md','2026-05-10T19:35:00Z','session_2026-05-10c-protocol-redo.md',NULL,NULL,NULL,NULL);
INSERT INTO "gaps" VALUES('GAP-282','CD','P3','OPEN','item-specification-writer','A category','Item code A-02 is currently ''Acoustic Ceiling Panels (NRC ≥0.85) in Occupied Spaces'' (D=up). Simpson 2025 SR (REF-00642), the BPC evidence base for slug school-environment-autism, asserts RT60 specifications for school occupied spaces. There is no item code for ''RT60 in occupied school spaces'' (A-10b is RT60 for hydrotherapy/pool — different scope). Either (a) Simpson 2025''s RT60 spec needs a new A-NN item, or (b) the BPC''s RT60 reference should map to a different item. Surfaced by audit Stage B.5 (session 2026-05-10c). Was initially flagged as handoff staleness but is genuinely a missing item. P3 because the NRC item still goes through PMP under the current numbering.','2026-05-10T19:35:00Z','session_2026-05-10c-protocol-redo.md','2026-05-10T19:35:00Z','session_2026-05-10c-protocol-redo.md',NULL,NULL,NULL,NULL);
