INSERT INTO "spec_value_probes" VALUES('PMP-A08-001-F','PMP-A08-001','school-environment-autism','A-08',25.0,'NC','down','AUT, PCS, DEM, MH, PAIN, OFS','maximum',3,'final',25.0,'NC',NULL,NULL,NULL,NULL,'V_empirical_ceiling=25 (NC-25). gap_signed=0. BPC value matches ANSI S12.60 HVAC component exactly. Note: ANSI S12.60 explicitly excludes "special education rooms such as those for severely acoustically challenged students" — no autism-specific NC standard exists.','2026-05-10T20:39:54Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-A02-001-F','PMP-A02-001','school-environment-autism','A-02',0.85,'NRC','up','ALL','minimum',6,'final',0.935,'NRC',NULL,NULL,NULL,NULL,'V_empirical_ceiling=0.935 (NRC). Rounding to standard spec: NRC 0.90. gap_signed=+0.05. BPC spec (NRC ≥0.85) is BELOW ANSI S12.60 S5.3 minimum (NRC 0.90). BPC could raise threshold to NRC ≥0.90 to match standards evidence. ANSI/GBI 01-2019 also requires NRC 0.90 for healthcare/eldercare.','2026-05-10T20:39:54Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-A08-001-S1','PMP-A08-001','school-environment-autism','A-08',25.0,'NC','down','AUT, PCS, DEM, MH, PAIN, OFS','maximum',1,'outer-stop',20.0,'NC','NC-20 classroom noise criterion autism HVAC maximum','background noise level NC-20 school sensitive population autism dementia',0,NULL,'NC-20 ultra-quiet (studios/libraries per ASHRAE). No source specifies NC-20 for school. ANSI S12.60 HVAC ≈ NC-25. Both primary and alt queries fail.','2026-05-10T20:40:34Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-A08-001-S2','PMP-A08-001','school-environment-autism','A-08',25.0,'NC','down','AUT, PCS, DEM, MH, PAIN, OFS','maximum',2,'refinement-stop',24.0,'NC','NC-24 classroom HVAC noise standard school',NULL,0,NULL,'NC-24 not in any standard. Distance to floor=1=δ_min. STOP.','2026-05-10T20:40:34Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-A02-001-S1','PMP-A02-001','school-environment-autism','A-02',0.85,'NRC','up','ALL','minimum',1,'outer-stop',1.02,'NRC','NRC 1.0 acoustic ceiling panel classroom ANSI S12.60 school',NULL,0,NULL,'NRC 1.02 exceeds any standard. Both queries fail.','2026-05-10T20:40:34Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-A02-001-S2','PMP-A02-001','school-environment-autism','A-02',0.85,'NRC','up','ALL','minimum',2,'refinement-pass-1st',0.935,'NRC','NRC 0.90 classroom ceiling ANSI S12.60 minimum',NULL,1,'REF-00335','ANSI S12.60 S5.3: "ceiling minimum NRC 0.90." ANSI/GBI 01-2019 requires NRC 0.90 for patient/eldercare. 0.935 within "0.90 or higher." PASS.','2026-05-10T20:40:34Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-A02-001-S3','PMP-A02-001','school-environment-autism','A-02',0.85,'NRC','up','ALL','minimum',3,'refinement-stop',0.975,'NRC','NRC 0.95 classroom ceiling acoustic standard',NULL,0,NULL,'No standard specifies NRC 0.975. "Possibly higher" is guidance not specification.','2026-05-10T20:40:34Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-A02-001-S4','PMP-A02-001','school-environment-autism','A-02',0.85,'NRC','up','ALL','minimum',4,'refinement-stop',0.955,'NRC','NRC 0.95 ceiling GBI healthcare classroom',NULL,0,NULL,'No standard specifies NRC 0.955.','2026-05-10T20:40:34Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-A02-001-S5','PMP-A02-001','school-environment-autism','A-02',0.85,'NRC','up','ALL','minimum',5,'refinement-stop',0.945,'NRC',NULL,NULL,0,NULL,'Refinement 0.935-0.945. Distance=0.01 > δ_min. No standard at 0.945.','2026-05-10T20:40:34Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-A02-001-S6','PMP-A02-001','school-environment-autism','A-02',0.85,'NRC','up','ALL','minimum',6,'refinement-stop',0.94,'NRC',NULL,NULL,0,NULL,'Distance floor-fail = 0.005 = δ_min. STOP. V_empirical_ceiling = 0.935 ≈ NRC 0.90.','2026-05-10T20:40:34Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-B01-001-S1','PMP-B01-001','circadian-lighting-melanopic-edi','B-01',150.0,'EML','up','ALL','minimum',1,'outer-pass-1st',180.0,'EML','melanopic EDI circadian lighting minimum 250 recommendation Brown 2022',NULL,1,'REF-00551','Brown 2022 (PMC8929548) recommends ≥250 m-EDI ≈ 275 EML. 180 EML well within supported range. PASS.','2026-05-10T21:21:30Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-B01-001-S2','PMP-B01-001','circadian-lighting-melanopic-edi','B-01',150.0,'EML','up','ALL','minimum',2,'outer-pass-1st',216.0,'EML',NULL,NULL,1,'REF-00551','216 EML ≈ 196 m-EDI. Below Brown 2022 consensus (250 m-EDI). WELL v2 L03 = 218 m-EDI. PASS.','2026-05-10T21:21:30Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-B01-001-S3','PMP-B01-001','circadian-lighting-melanopic-edi','B-01',150.0,'EML','up','ALL','minimum',3,'outer-pass-1st',259.0,'EML',NULL,NULL,1,'REF-00551','259 EML ≈ 235 m-EDI. Below Brown 2022 consensus. PASS.','2026-05-10T21:21:30Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-B01-001-S4','PMP-B01-001','circadian-lighting-melanopic-edi','B-01',150.0,'EML','up','ALL','minimum',4,'outer-stop',311.0,'EML','melanopic EDI 300 minimum circadian lighting recommendation',NULL,0,NULL,'311 EML ≈ 283 m-EDI. Brown 2022 specifies ≥250 m-EDI, not ≥283. No source specifies higher minimum. FAIL.','2026-05-10T21:21:30Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-B01-001-S5','PMP-B01-001','circadian-lighting-melanopic-edi','B-01',150.0,'EML','up','ALL','minimum',5,'refinement-pass-1st',285.0,'EML','melanopic EDI 250 260 Brown 2022 consensus recommendation',NULL,1,'REF-00551','285 EML ≈ 259 m-EDI. Brown 2022 specifies ≥250 m-EDI. 259 within ±10 of 250. PASS.','2026-05-10T21:21:30Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-B01-001-S6','PMP-B01-001','circadian-lighting-melanopic-edi','B-01',150.0,'EML','up','ALL','minimum',6,'refinement-stop',298.0,'EML',NULL,NULL,0,NULL,'298 EML ≈ 271 m-EDI. No source specifies ≥271 m-EDI as minimum. FAIL.','2026-05-10T21:21:30Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-B01-001-S7','PMP-B01-001','circadian-lighting-melanopic-edi','B-01',150.0,'EML','up','ALL','minimum',7,'refinement-stop',291.0,'EML',NULL,NULL,0,NULL,'Refinement narrowing. 291 EML ≈ 264 m-EDI. No source at 264. FAIL. Distance to floor=6 < δ_min=10. STOP.','2026-05-10T21:21:30Z','session_2026-05-10e-slug3-adversarial');
INSERT INTO "spec_value_probes" VALUES('PMP-B01-001-F','PMP-B01-001','circadian-lighting-melanopic-edi','B-01',150.0,'EML','up','ALL','minimum',8,'final',285.0,'EML',NULL,NULL,NULL,NULL,'V_empirical_ceiling = 285 EML (≈259 m-EDI, nearest to Brown 2022 consensus of ≥250 m-EDI ≈ 275 EML). gap_signed = +135 EML. BPC spec (≥150 EML) is LESS THAN HALF the evidence-supported minimum. TWO corrections needed: (1) metric migration EML → melanopic EDI per CIE S 026:2018, (2) threshold raise 150 → ≥250 melanopic EDI per Brown 2022. NOTE: T/SIEATA (Chinese classroom standard) is the only standards-track document specifying m-EDI for educational spaces.','2026-05-10T21:21:30Z','session_2026-05-10e-slug3-adversarial');
