CREATE TABLE "gaps" (
    gap_id              TEXT PRIMARY KEY,
    category            TEXT NOT NULL
                        CHECK(category IN (
                            'RP','SW','CR','ST','MX','CD','EC','EG',
                            'CI','DEC','CONF','AUDT'
                        )),
    priority            TEXT NOT NULL CHECK(priority IN ('P1','P2','P3')),
    status              TEXT NOT NULL
                        CHECK(status LIKE 'OPEN%' OR status LIKE 'CLOSED%'),
    skill               TEXT,
    section             TEXT,
    description         TEXT NOT NULL,
    created_at          TEXT NOT NULL,
    created_by_session  TEXT NOT NULL,
    updated_at          TEXT NOT NULL,
    updated_by_session  TEXT NOT NULL
, falsification_condition TEXT, confidence_interval TEXT, shift_conditions TEXT, named_dissenter TEXT);
CREATE TABLE item_audit_runs (
    run_id              TEXT PRIMARY KEY,
    item_code           TEXT NOT NULL REFERENCES items(item_code),
    session             TEXT NOT NULL,
    steps_complete      TEXT NOT NULL DEFAULT '[]',
    steps_started       TEXT NOT NULL DEFAULT '[]',
    status              TEXT NOT NULL DEFAULT 'IN-PROGRESS'
                        CHECK(status IN ('IN-PROGRESS','COMPLETE','HANDED-OFF')),
    spec_hash           TEXT,
    brief_path          TEXT,
    created_at          TEXT NOT NULL,
    created_by_session  TEXT NOT NULL,
    updated_at          TEXT NOT NULL,
    updated_by_session  TEXT NOT NULL
);
CREATE TABLE item_population_elaborations (
  elab_id             INTEGER PRIMARY KEY AUTOINCREMENT,
  item_code           TEXT NOT NULL REFERENCES items(item_code) ON DELETE CASCADE,
  population_code     TEXT NOT NULL REFERENCES populations(population_code),
  variant_distinction TEXT,
  spec_variant_a      TEXT,
  spec_variant_b      TEXT,
  evidence_ref_id     TEXT REFERENCES evidence_sources(ref_id),
  notes               TEXT,
  created_at          TEXT,
  created_by_session  TEXT,
  UNIQUE(item_code, population_code, variant_distinction)
);
CREATE TABLE item_population_links (
  item_code           TEXT NOT NULL,
  population_code     TEXT NOT NULL REFERENCES populations(population_code),
  subtype             TEXT NOT NULL DEFAULT '',  -- '' = no subtype; use empty string so PK works
  applicability       TEXT NOT NULL DEFAULT 'applies' CHECK(applicability IN (
                        'applies', 'applies_strictly', 'applies_loosely',
                        'context_dependent', 'does_not_apply'
                      )),
  rationale_ref       INTEGER,
  created_at          TEXT,
  created_by_session  TEXT,
  PRIMARY KEY (item_code, population_code, subtype),
  FOREIGN KEY (item_code) REFERENCES items(item_code) ON DELETE CASCADE
);
CREATE TABLE items (
    item_code           TEXT PRIMARY KEY,
    item_id             TEXT UNIQUE,
    category            TEXT NOT NULL
                        CHECK(category IN (
                            'A','B','C','D','E','F','G','H','I','J','K'
                        )),
    name                TEXT NOT NULL,
    bpc_source_slug     TEXT REFERENCES slugs(slug),
    status              TEXT NOT NULL DEFAULT 'draft'
                        CHECK(status IN ('draft','active','merged','retired')),
    created_at          TEXT NOT NULL,
    created_by_session  TEXT NOT NULL,
    updated_at          TEXT NOT NULL,
    updated_by_session  TEXT NOT NULL
, pmp_delta_min          REAL, pmp_direction          TEXT, pmp_last_walk_at       TEXT, pmp_empirical_ceiling  REAL, pmp_gap_signed         REAL);
CREATE TABLE pipeline_runs (
          run_id             TEXT PRIMARY KEY,
          started_at         TEXT NOT NULL,
          completed_at       TEXT,
          phase_0_extracted  INTEGER DEFAULT 0,
          phase_1a_resolved  INTEGER DEFAULT 0,
          phase_1a_no_match  INTEGER DEFAULT 0,
          phase_1a_transient INTEGER DEFAULT 0,
          phase_1b_resolved  INTEGER DEFAULT 0,
          phase_1b_no_match  INTEGER DEFAULT 0,
          phase_1b_transient INTEGER DEFAULT 0,
          phase_2a_resolved  INTEGER DEFAULT 0,
          phase_2a_no_match  INTEGER DEFAULT 0,
          phase_2b_resolved  INTEGER DEFAULT 0,
          phase_2b_no_match  INTEGER DEFAULT 0,
          phase_3_resolved   INTEGER DEFAULT 0,
          phase_3_no_match   INTEGER DEFAULT 0,
          doi_before         INTEGER DEFAULT 0,
          doi_after          INTEGER DEFAULT 0,
          verified_before    INTEGER DEFAULT 0,
          verified_after     INTEGER DEFAULT 0,
          pmcid_before       INTEGER DEFAULT 0,
          pmcid_after        INTEGER DEFAULT 0,
          total_resolved     INTEGER DEFAULT 0,
          run_by_session     TEXT
        , phase_4_enriched INTEGER DEFAULT 0, phase_4_complete INTEGER DEFAULT 0, phase_4_transient INTEGER DEFAULT 0, metadata_complete_before INTEGER DEFAULT 0, metadata_complete_after INTEGER DEFAULT 0);
CREATE TABLE populations (
  population_code     TEXT PRIMARY KEY,
  display_name        TEXT NOT NULL,
  category            TEXT CHECK(category IN (
                        'mobility', 'sensory', 'cognitive', 'mental_health',
                        'pain_fatigue', 'neurological', 'developmental',
                        'general'
                      )),
  description         TEXT,
  parent_code         TEXT REFERENCES populations(population_code),
  is_compound         INTEGER DEFAULT 0 CHECK(is_compound IN (0,1)),
  status              TEXT DEFAULT 'active' CHECK(status IN ('active', 'deprecated')),
  created_at          TEXT,
  updated_at          TEXT
);
CREATE TABLE reasoning_doc_citations (
    citation_id          TEXT PRIMARY KEY,
    reasoning_doc_slug   TEXT NOT NULL,
    parameter            TEXT NOT NULL,
    jurisdiction         TEXT,
    population           TEXT,
    claim_type           TEXT NOT NULL CHECK(claim_type IN (
        'numerical_spec','jurisdiction_value','qualitative','definitional'
    )),
    claimed_value        TEXT,
    claimed_unit         TEXT,
    claim_text           TEXT,
    source_ref_id        TEXT NOT NULL REFERENCES evidence_sources(ref_id),
    source_section       TEXT,
    value_match          TEXT CHECK(value_match IN (
        'EXACT','WITHIN-TOLERANCE','DIFFERENT','NOT-FOUND','PAYWALL','SUPERSEDED'
    )),
    claim_match          TEXT CHECK(claim_match IN (
        'SUPPORTED','PARTIAL','NOT-FOUND','PAYWALL','CONTRADICTED'
    )),
    verified_at          TEXT NOT NULL,
    verified_by_session  TEXT NOT NULL,
    paywall_purchase_candidate INTEGER NOT NULL DEFAULT 0 CHECK(paywall_purchase_candidate IN (0,1)),
    notes                TEXT,
    CHECK (
      (claim_type IN ('numerical_spec','jurisdiction_value') AND claimed_value IS NOT NULL AND value_match IS NOT NULL) OR
      (claim_type IN ('qualitative','definitional') AND claim_text IS NOT NULL AND claim_match IS NOT NULL)
    )
);
CREATE TABLE search_coverage (
    slug                TEXT NOT NULL REFERENCES slugs(slug),
    jurisdiction        TEXT NOT NULL,
    status              TEXT NOT NULL
                        CHECK(status IN ('SEARCHED','THIN','NO-DATA','NOT-RUN')),
    co1_attempted       INTEGER NOT NULL DEFAULT 0 CHECK(co1_attempted IN (0,1)),
    tier5_attempted     INTEGER NOT NULL DEFAULT 0 CHECK(tier5_attempted IN (0,1)),
    tier6_attempted     INTEGER NOT NULL DEFAULT 0 CHECK(tier6_attempted IN (0,1)),
    notes               TEXT,
    created_at          TEXT NOT NULL,
    created_by_session  TEXT NOT NULL,
    updated_at          TEXT NOT NULL,
    updated_by_session  TEXT NOT NULL,
    PRIMARY KEY (slug, jurisdiction)
);
CREATE TABLE search_languages (
    slug                TEXT NOT NULL REFERENCES slugs(slug),
    language            TEXT NOT NULL,
    status              TEXT NOT NULL
                        CHECK(status IN ('SEARCHED','PARTIAL','NOT-RUN')),
    results_count       INTEGER NOT NULL DEFAULT 0,
    notes               TEXT,
    created_at          TEXT NOT NULL,
    created_by_session  TEXT NOT NULL,
    updated_at          TEXT NOT NULL,
    updated_by_session  TEXT NOT NULL,
    PRIMARY KEY (slug, language)
);

