CREATE TABLE slugs (
    slug                TEXT PRIMARY KEY,
    topic_directory     TEXT NOT NULL,
    sl_path             TEXT NOT NULL,
    bpc_path            TEXT NOT NULL,
    status              TEXT NOT NULL
                        CHECK(status IN (
                            'ACTIVE','MERGED','STUB','PROVISIONAL'
                        )),
    merged_into         TEXT,
    created_at          TEXT NOT NULL,
    created_by_session  TEXT NOT NULL,
    updated_at          TEXT NOT NULL,
    updated_by_session  TEXT NOT NULL
);
CREATE TABLE "source_slug_links" (
    ref_id              TEXT NOT NULL REFERENCES evidence_sources(ref_id),
    slug                TEXT NOT NULL REFERENCES slugs(slug),
    local_ref_id        TEXT NOT NULL,
    created_at          TEXT NOT NULL,
    created_by_session  TEXT NOT NULL,
    updated_at          TEXT NOT NULL,
    updated_by_session  TEXT NOT NULL,
    PRIMARY KEY (ref_id, slug)
);
CREATE TABLE "spec_value_probes" (
    probe_id            TEXT PRIMARY KEY,
    walk_id             TEXT NOT NULL,
    slug                TEXT NOT NULL,
    item_code           TEXT NOT NULL REFERENCES items(item_code),
    spec_value_origin   REAL NOT NULL,
    spec_unit           TEXT NOT NULL,
    direction           TEXT NOT NULL CHECK (direction IN ('up','down')),
    population          TEXT NOT NULL,
    claim_type          TEXT NOT NULL
                        CHECK (claim_type IN (
                            'minimum','maximum','target','range_low','range_high'
                        )),
    step_index          INTEGER NOT NULL,
    phase               TEXT NOT NULL
                        CHECK (phase IN (
                            'outer-pass-1st','outer-pass-2nd','outer-stop',
                            'refinement-pass-1st','refinement-pass-2nd','refinement-stop',
                            'final'
                        )),
    step_value          REAL NOT NULL,
    step_value_unit     TEXT NOT NULL,
    search_query        TEXT,
    search_query_alt    TEXT,
    passes_strict       INTEGER CHECK (passes_strict IN (0,1)),
    ref_id              TEXT REFERENCES evidence_sources(ref_id),
    notes               TEXT,
    created_at          TEXT NOT NULL,
    created_by_session  TEXT NOT NULL
);
CREATE TABLE term_aliases (
    term_id             TEXT NOT NULL REFERENCES terms(term_id),
    alias               TEXT NOT NULL,
    language            TEXT NOT NULL DEFAULT 'EN',
    alias_type          TEXT NOT NULL
                        CHECK(alias_type IN (
                            'SYNONYM','TRANSLATION','NARROWER',
                            'BROADER','DEPRECATED','DOMAIN'
                        )),
    jurisdiction        TEXT,
    notes               TEXT,
    created_at          TEXT NOT NULL,
    created_by_session  TEXT NOT NULL,
    updated_at          TEXT NOT NULL,
    updated_by_session  TEXT NOT NULL,
    PRIMARY KEY (term_id, alias, language)
);
CREATE TABLE term_item_links (
    term_id             TEXT NOT NULL REFERENCES terms(term_id),
    item_code           TEXT NOT NULL,
    population          TEXT,
    notes               TEXT,
    created_at          TEXT NOT NULL,
    created_by_session  TEXT NOT NULL,
    updated_at          TEXT NOT NULL,
    updated_by_session  TEXT NOT NULL,
    PRIMARY KEY (term_id, item_code)
);
CREATE TABLE terms (
    term_id             TEXT PRIMARY KEY,
    canonical_en        TEXT NOT NULL,
    definition          TEXT,
    domain              TEXT,
    scope_note          TEXT,
    created_at          TEXT NOT NULL,
    created_by_session  TEXT NOT NULL,
    updated_at          TEXT NOT NULL,
    updated_by_session  TEXT NOT NULL
);
CREATE TABLE url_verification_runs (
          run_id              TEXT PRIMARY KEY,
          started_at          TEXT NOT NULL,
          completed_at        TEXT,
          candidates_pool     INTEGER DEFAULT 0,
          attempted           INTEGER DEFAULT 0,
          verified            INTEGER DEFAULT 0,
          probabilistic       INTEGER DEFAULT 0,
          no_match            INTEGER DEFAULT 0,
          dead                INTEGER DEFAULT 0,
          wayback_verified    INTEGER DEFAULT 0,
          wayback_probabilistic INTEGER DEFAULT 0,
          dead_dns            INTEGER DEFAULT 0,
          transient           INTEGER DEFAULT 0,
          verified_before     INTEGER DEFAULT 0,
          verified_after      INTEGER DEFAULT 0,
          run_by_session      TEXT
        );
CREATE INDEX idx_conn_status     ON connections(status);
CREATE INDEX idx_conn_confidence ON connections(confidence);
CREATE INDEX idx_conn_filed_in   ON connections(filed_in);
CREATE INDEX idx_ct_target       ON connection_targets(target);
CREATE INDEX idx_es_doi      ON "evidence_sources_v1_legacy"(doi);
CREATE INDEX idx_es_tier     ON "evidence_sources_v1_legacy"(tier);
CREATE INDEX idx_ta_alias    ON term_aliases(alias);
CREATE INDEX idx_ta_language ON term_aliases(language);
CREATE INDEX idx_til_item    ON term_item_links(item_code);
CREATE INDEX idx_decision_status   ON decisions(status);
CREATE INDEX idx_decision_category ON decisions(category);
CREATE INDEX idx_items_category ON items(category);
CREATE INDEX idx_items_slug     ON items(bpc_source_slug);
CREATE INDEX idx_audit_runs_item   ON item_audit_runs(item_code);
CREATE INDEX idx_audit_runs_status ON item_audit_runs(status);
CREATE UNIQUE INDEX idx_conflicts_dedup ON conflicts(item_code, domain, pop_a, pop_b);
CREATE INDEX idx_conflicts_status ON conflicts(status);
CREATE INDEX idx_conflicts_item   ON conflicts(item_code);
CREATE INDEX idx_gap_priority_status ON gaps(priority, status);
CREATE INDEX idx_data_migrations_applied_at ON data_migrations(applied_at);
CREATE INDEX idx_esa_ref_id ON evidence_source_authors(ref_id);
CREATE INDEX idx_esa_last   ON evidence_source_authors(last_name);
CREATE INDEX idx_esa_corp   ON evidence_source_authors(corporate_name);
CREATE INDEX idx_ipl_pop  ON item_population_links(population_code);
CREATE INDEX idx_ipl_item ON item_population_links(item_code);
CREATE INDEX idx_ipe_item ON item_population_elaborations(item_code);
CREATE VIEW v_pmp_latest_walk AS
SELECT
    item_code,
    slug,
    walk_id,
    MAX(created_at) AS walk_completed_at,
    SUM(CASE WHEN phase IN (
            'outer-pass-1st','outer-pass-2nd',
            'refinement-pass-1st','refinement-pass-2nd'
        ) THEN 1 ELSE 0 END) AS supported_steps,
    SUM(CASE WHEN phase IN (
            'outer-stop','refinement-stop'
        ) THEN 1 ELSE 0 END) AS terminator_steps
FROM spec_value_probes
GROUP BY item_code, slug, walk_id;
CREATE INDEX idx_ssl_slug ON source_slug_links(slug);
CREATE INDEX idx_ssl_ref  ON source_slug_links(ref_id);
CREATE INDEX idx_svp_slug_item  ON spec_value_probes(slug, item_code);
CREATE INDEX idx_svp_walk       ON spec_value_probes(walk_id, step_index);
CREATE INDEX idx_svp_item_phase ON spec_value_probes(item_code, phase);
CREATE INDEX idx_svp_ref        ON spec_value_probes(ref_id);
CREATE INDEX idx_cm_unmined ON citation_mining(slug, backward, forward);
CREATE INDEX idx_epm_ref ON evidence_population_match(ref_id);
CREATE INDEX idx_epm_gap ON evidence_population_match(gap_id);
CREATE INDEX idx_rdc_slug_param  ON reasoning_doc_citations(reasoning_doc_slug, parameter);
CREATE INDEX idx_rdc_ref         ON reasoning_doc_citations(source_ref_id);
CREATE INDEX idx_rdc_claim_type  ON reasoning_doc_citations(claim_type);
CREATE INDEX idx_rdc_paywall     ON reasoning_doc_citations(paywall_purchase_candidate) WHERE paywall_purchase_candidate = 1;
